@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a schema1:CreativeWork ;
                    schema1:encodingFormat "text/html" ;
                    schema1:name "User Documentation" ;
                    schema1:url "https://example.org/docs" ] ;
            sh:resultMessage "A collection/bundled object should specify at least one component resource (schema:hasPart)." ;
            sh:resultPath schema1:hasPart ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A collection/bundled object should specify at least one component resource (schema:hasPart)." ;
                    sh:minCount 1 ;
                    sh:path schema1:hasPart ;
                    sh:severity sh:Warning ] ] .
